{"command": "cd /tmp/sv-aabb729fe3df4c77ba9ec76726976616 && \
# Check what debuglink points to
readelf --string-dump=.gnu_debuglink libmonosgen-2.0.so 2>/dev/null && \
echo "=== Trying to symbolicate with dynamic symbols ===" && \
# Use addr2line / llvm tools if available
which llvm-symbolizer addr2line aarch64-linux-gnu-addr2line 2>/dev/null || echo "checking for tools..." && \
# Try nm on the exported symbols near our addresses
OFFSETS="0x222098 0x2241ac 0x1abc80 0x1abd14 0x16dfa4 0x16db6c 0x16de04" && \
for off in $OFFSETS; do
  echo -n "Frame at $off -> "
  nm -D --defined-only libmonosgen-2.0.so 2>/dev/null | awk -v addr="$off" '
    BEGIN { best=""; best_off=99999999 }
    {
      val = strtonum("0x" $1)
      target = strtonum(addr)
      if (val <= target && (target - val) < best_off) {
        best_off = target - val
        best = $3 " + 0x" sprintf("%x", best_off)
      }
    }
    END { print best }
  '
done", "description": "Symbolicate frames with dynamic symbols", "initial_wait": 15}
